import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer
} from 'recharts';

const data = [
  {
    month: 'Jan',
    leads: 12
  },
  {
    month: 'Feb',
    leads: 18
  },
  {
    month: 'Mar',
    leads: 25
  },
  {
    month: 'Apr',
    leads: 30
  }
];

function Reports() {
  return (
    <div>
      <h2>
        Reports & Analytics
      </h2>

      <div className="card">
        <h3>
          Monthly Lead Growth
        </h3>

        <ResponsiveContainer
          width="100%"
          height={300}
        >
          <BarChart data={data}>
            <XAxis dataKey="month" />

            <YAxis />

            <Tooltip />

            <Bar dataKey="leads" />
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

export default Reports;
